var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"어떡하지? 부사장님 신호가 안 잡혀.","JPN":"どうしよう？　副社長の信号が捉えられない。","ENG":"What do we do? There’s no signal from the Vice President.","TWN":"怎麼辦？副總那邊失去訊號了！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"교신 기록으로는 분명 이 근처일 텐데…….","JPN":"交信記録によると、この辺で合ってるはずなんだけど……","ENG":"According to the record, it's got to be somewhere around here...","TWN":"從通訊記錄來看，應該就在這附近……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"안심하세요, 레나 양.","JPN":"安心してください、レナ。","ENG":"Don't worry, Lena.","TWN":"別擔心，蕾娜。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"연봉 협상의 가장 큰 장애물이 이대로 쉽게 사라질 리 없어요.","JPN":"年俸交渉の最大の邪魔者がこのまま簡単に消えてくれるわけがありません。","ENG":"I'm pretty sure our biggest obstacle in getting a salary raise won't go away that easily.","TWN":"薪資協商的最大阻礙是不會就這樣輕易消失的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"농담할 때가 아니잖아, 클로에!","JPN":"冗談を言っている場合じゃないわよ、クロエ！","ENG":"Now's not the time for jokes, Chloe!","TWN":"現在不是開玩笑的時候，克洛伊！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"엔터프라이즈를 추격하려는 적들을 막으러 가신 뒤로 통신이 두절됐어.","JPN":"エンタープライズを追撃しようとする敵を食い止めに行ったきりで、通信が途絶えてるのよ。","ENG":"We've lost her signal after she went to stop the enemies chasing down the Enterprise.","TWN":"在她去阻止試圖追擊企業號的敵人後，通訊就中斷了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"그런데 정작 그 적들은 아무데도 안 보이고…….","JPN":"それなのに、肝心の敵はどこにも見えないし……","ENG":"But they're nowhere to be seen...","TWN":"而且那些敵人也全都消失了……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"만에 하나라도 부사장님이 잘못되기라도 하면 어떡해?","JPN":"万が一副社長の身に何かあったらどうしよう？","ENG":"What if something happened to the Vice President?","TWN":"萬一副總出事了怎麼辦？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"……레나 양. 전 농담을 한 게 아니에요.","JPN":"……レナ、私は冗談を言ったわけじゃありませんよ。","ENG":"...I wasn't joking around just now, Lena.","TWN":"……我沒在開玩笑，蕾娜。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"무슨 소리야, 그게?","JPN":"どういうこと、それ？","ENG":"What do you mean?","TWN":"你這話是什麼意思？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"이 회사에 취직한 뒤로 하루도 빠짐없이 수호령께 기도드렸어요.","JPN":"この会社に就職してから、私は一日も欠かさずに守護霊に祈り続けてきました。","ENG":"Since day one of working here, I’ve been praying to the guardian spirit every single day.","TWN":"從來這家公司上班開始，我每天都會向守護靈祈禱。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"근로 환경 악화의 주범인 부사장님이 한동안 병원 신세를 지게 해 달라고.","JPN":"職場環境の悪化の最たる原因である副社長をしばらくの間病院送りにしてくれ、と。","ENG":"I prayed for our workplace nightmare–the Vice President–to be hospitalized for a long time.","TWN":"祈禱我們的職場噩夢能去醫院住上一段時間。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"그런데 제 정성 들인 저주에도 언제나 멀쩡한 모습으로 출근하더군요.","JPN":"でも、そんな私の精魂を込めた呪いにも関わらず、いつも平気で出社してくる人なんです。","ENG":"Alas, my desperate prayers never worked. Every day, she would come to work, without a scratch.","TWN":"可是哪怕我如此虔誠地詛咒，她還是每天都四肢健全地出現在公司。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"그러니까…… 절대 죽지 않을 거예요.","JPN":"だから……決して死ぬことはありません。","ENG":"That is why I'm telling you... She is not going to die.","TWN":"所以……她是絕對不會死的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"클로에?","JPN":"クロエ？","ENG":"Chloe?","TWN":"克洛伊？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"너…… 눈이 왜 그렇게 빨개?","JPN":"……どうしたの、目が赤いよ？","ENG":"Your... Your eyes look really red.","TWN":"你……你的眼睛怎麼紅了？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"혹시 나 몰래 울었던 건…….","JPN":"もしかしてこっそり泣いていたんじゃ……","ENG":"Have you been cry–","TWN":"你是不是背著我哭過了……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"크흠! 흠!","JPN":"ゴホン！　ゴホン！","ENG":"Ahem! Hmm!","TWN":"咳咳！咳！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"식별 신호 감지.","JPN":"識別信号を検出。","ENG":"Biometric signal detected.","TWN":"感應到識別訊號。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"침식파 탓에 노이즈가 심하지만, 부사장님의 패턴과 94% 가량 일치합니다.","JPN":"侵食波のせいでノイズが酷いですが、副社長のパターンと94％一致しています。","ENG":"The Corruption ray is making the signal fuzzy, but it's a 94% match with the Vice President.","TWN":"雖然在侵蝕波的影響下訊號很模糊，但和副總的匹配度達到了94%！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"보정을 고려했을 때의 오차율은…… 약 ±0.37%.","JPN":"補正を考慮すると、誤差は……約±0.37％。","ENG":"Considering the correction factor, the margin of error would be... approximately ±0.37%.","TWN":"考慮到修正值，誤差率……大約為±0.37%！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"저, 정말?! 그럼 본인이 확실하단 거잖아!","JPN":"ほ、本当！？　じゃあほとんど本人で間違いないね！","ENG":"R-really? That means it's her!","TWN":"真，真的嗎？！那豈不是確定就是本人！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"네. 문제는 본 함을 향해 저속으로 이동 중인데…….","JPN":"はい、ただ本艦に向かって低速で移動してきているのですが……","ENG":"Yes. The problem is, while the signal is moving towards this fleet at low speed...","TWN":"嗯，但問題是，艦船一直朝著本艦的方向低速移動……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"바이탈 사인은 현재 의식 불명 상태로 계측됩니다.","JPN":"バイタルサインは現在、意識不明状態となっています。","ENG":"And vital signs show that the subject is unconscious.","TWN":"感應到的生命訊號顯示她目前是昏迷狀態。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"뭐? 그럼 어떻게 이리로 오고 계시다는 거야?","JPN":"え？　じゃあどうやってこっちに向かってきているというの？","ENG":"What? How is she moving towards us, then?","TWN":"什，什麼！那艦船是怎麼動起來的？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"아, 아니지. 가서 우리 눈으로 직접 확인해 보자.","JPN":"ううん、違う。直接確認しに行こう。","ENG":"Wait, never mind. Let's go and see for ourselves.","TWN":"不，不行，我們親自去看看吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"항로를 수정할게! 클로에는 계속 통신을 시도해 봐!","JPN":"航路を修正！　クロエはそのまま通信を試して！","ENG":"I'm changing the route! Chloe, keep the comms going!","TWN":"我來修改航線！克洛伊你繼續嘗試通訊！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"큭……. 으윽…….","JPN":"くっ……ううっ……","ENG":"Kgh... Ngh...","TWN":"唔……咳咳咳……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"코핀 함의 소리야. 직원들이 찾으러 오나 보네.","JPN":"コフィン艦の音だ……社員たちが迎えに来たみたいだね。","ENG":"That's the sound of Coffin. Your employees are coming here.","TWN":"是科芬艦的通訊，看來你的那群小職員找來了啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"조금만 참아, 수연아. 거의 다 왔으니까.","JPN":"少しだけ耐えて、キズナ。あともう少しだ。","ENG":"Hold on, Sooyeon. We're almost there.","TWN":"再堅持一下，秀妍。就快到了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지금까지 고생 많았어. 이제는 푹 쉬어야지.","JPN":"今までよく頑張ったね。あとはゆっくり休まないと。","ENG":"You've done well. You need some rest now.","TWN":"這段時間你受苦了，現在好好休息吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그나저나 이렇게 안아 드니까 옛날 생각 나네.","JPN":"それにしても、こういうふうに抱きかかえていると、昔を思い出すな。","ENG":"Holding you like this reminds me of the old days.","TWN":"不過這樣抱著你，倒是讓我想起了以前的事。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"네가 날뛰다가 부상 입은 날이면 의료실까지 데려가는 건 늘 내 몫이었지.","JPN":"君が暴れて怪我をすれば、治療室まで運ぶのはいつだって僕の役目だった。","ENG":"I was always in charge of taking you to the infirmary, whenever you went on a rampage and hurt yourself.","TWN":"每次你因為胡鬧而受傷，都是我負責送去醫務室的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"다른 전대원들 눈에 띄면 스승님 이름에 먹칠을 했다면서 펄펄 뛰었고.","JPN":"それが他の戦隊員たちにバレると、師匠の顔に泥を塗ったと言ってすごく怒ってたっけ。","ENG":"You would get furious when the other divisions spotted you, yelling that you were being a disgrace to Master's honor.","TWN":"被戰隊其他隊員看到的時候，還跳著腳嚷嚷什麼“給師父丟臉了”之類的話。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 정말 한결같네. 여전히 어릴 때처럼 나서지 않고는 못배기다니.","JPN":"はは、本当に君は変わらないね。小さい頃から自分が行かないと我慢できないその性格は。","ENG":"Ha ha. You never change, do you? You just can't resist the spotlight.","TWN":"哈哈，你真是一點都沒變。還是像小時候一樣，忍不住會站出來。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……그 날 이후로는 현장에 돌아오지 않길 바랐는데 말이야.","JPN":"……あの日以来、もう現場に戻ってきてほしくなかったんだけど。","ENG":"...I really hoped you wouldn't have to come back to the field after that day.","TWN":"……我真希望，自那天之後，你就再也不用回到前線。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇지 않나요? 관리자님.","JPN":"そうですよね？　管理者さん。","ENG":"Don't you agree, Administrator?","TWN":"不是嗎，管理者？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무렴. 동업하는 입장으로서 보고 있기 조마조마하지.","JPN":"ああ。同業者として見ていてハラハラする。","ENG":"Of course. It makes me feel uneasy, watching her.","TWN":"……當然。站在合夥人的立場上，我看著也是提心吊膽的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그만큼 부사장에게는 항상 고마워하고 있다네.","JPN":"その分、副社長にはいつも感謝している。","ENG":"But I’m also grateful for her work.","TWN":"所以我心裡一直很感謝副總。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"부사장이 아니었으면 여기까지 올 수도 없었겠지.","JPN":"副社長がいなければ、ここまでたどり着くことはできなかった。","ENG":"If it wasn't for her, we wouldn't have come this far.","TWN":"要不是副總，我們根本不可能走到這一步。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"수연이가 의식을 잃어서 아쉽네요.","JPN":"キズナが気を失っていることが残念ですね。","ENG":"It's a shame that Sooyeon lost consciousness.","TWN":"很可惜，秀妍昏迷了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 얘기를 들었으면 꽤 재밌는 반응이 나왔을 텐데요.","JPN":"その言葉を聞いていたら、まぁ面白い反応をしていたと思いますよ。","ENG":"It would’ve been interesting to watch her react to what you've just said.","TWN":"如果聽到這句話，她一定會做出有趣的反應吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 부사장이 홧김에 휘두른 주먹에도 멀쩡하겠지만, 나는 아니야. 사양하지.","JPN":"君は怒った副社長から拳が飛んできても無事だろうが、私は違う。遠慮させてくれ。","ENG":"Not so much. While you will be fine taking a punch or two from her, I won't.","TWN":"哈哈……你能承受住副總含怒揮出的拳頭，我可不行。還是算了吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하. 저라고 꼭 그렇지만도 않아요.","JPN":"はは、僕だってそうでもないですよ。","ENG":"Ha ha, I can't say that I will be fine either.","TWN":"哈哈，我也承受不了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"겸손이 과하군. 부사장의 상태는 어떤가?","JPN":"そんなに謙遜しなくていいぞ。副社長はどんな状態だ？","ENG":"That is very humble of you. Speaking of which, how is she?","TWN":"你太謙虛了，副總的狀態怎麼樣了？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리 좋진 않습니다. 목숨만 건졌을 뿐이죠.","JPN":"あまり良くはありません。とりあえず命だけはある状態です。","ENG":"Not so good. She barely made it out alive.","TWN":"不太好，只是保住了性命而已。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"혼자 기사단의 발을 묶어 둔 대가치고는……. 상당히 싸게 먹힌 셈이지만요.","JPN":"たった一人で騎士団を足止めした代償にしては、軽く済みましたけどね。","ENG":"Although it was a very cheap price... for keeping the Knights busy.","TWN":"作為一個人拖住騎士團手腳的代價……可以算是相當便宜了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇군. 연말에 보너스라도 넉넉하게 챙겨 줘야겠어.","JPN":"そうだな。年末ボーナスをたっぷり渡してやらねば。","ENG":"I see. I will make sure to pay her handsomely by the end of the year.","TWN":"是啊……看來年底我得好好獎勵她了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"모쪼록 잘 챙겨 주시면 좋겠네요. 저에게는 여전히 사고뭉치 동생 같아서요.","JPN":"良くしてやってください。僕からすればまだまだわんぱくな妹みたいで。","ENG":"Please do. She's still like a reckless little sister to me.","TWN":"希望你好好照顧她，對我來說，她還是那個愛闖禍的妹妹。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"자, 그럼… 이제 다음 단계로 넘어가야 할 시기였던가요?","JPN":"さて、それでは……そろそろ次の段階に移行するタイミングでしたっけ？","ENG":"Now, then... Is this the time to take the next step?","TWN":"好了……那接下來該進入下個階段了嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아, 죄송합니다. 대답하면 문제가 될 부분인가 보네요.","JPN":"あ、すみません。答えられないような質問でしたか。","ENG":"Oh, sorry. I see it's something you cannot be talking about.","TWN":"啊，對不起。看來你不好回答這個問題。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그것 역시 클리포트 게임의 규칙이겠죠?","JPN":"きっと、それもまた、クリフォトゲームのルールなんですよね？","ENG":"That must be the rules of the Qliphoth Game, no?","TWN":"這也是逆卡巴拉遊戲的規則吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 나는 이번 게임에 직접적으로 개입해서는 안 된다네.","JPN":"ああ。私は今回のゲームに直接的に関与してはいけないことになっている。","ENG":"Yes. I am prohibited from affecting this game in any way.","TWN":"是的，我不能直接介入這場戰役。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그녀와 마찬가지로 말일세.","JPN":"彼女と同じく、だ。","ENG":"That goes the same for her.","TWN":"和她一樣。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 규칙에 얽매여 사는 건 꽤 피곤한 일이긴 하죠.","JPN":"はは、ルールに縛られて生きるのは疲れますよね。","ENG":"Ha ha, it must be tiresome to live with so many restrictions.","TWN":"噢，被規則束縛這件事確實挺累人的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 걱정 마세요.","JPN":"でも心配しないでください。","ENG":"But don't you worry.","TWN":"不過請不用擔心。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"결국 저와 관리자님의 목적은……. 처음부터 줄곧 같았으니까요.","JPN":"僕と管理者さんの目的は……初めからずっと同じですから。","ENG":"Our goals... were always aligned with each other.","TWN":"因為我和管理者的目的……自始至終都是一樣的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"부사장님 발견. 공개 통신 거리에 진입했습니다.","JPN":"副社長を発見。公開通信距離内に進入しました。","ENG":"Vice President detected. Approaching open communication distance.","TWN":"發現副總，已經進入公開通訊距離。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"기다려, 클로에!","JPN":"待って、クロエ！","ENG":"Wait, Chloe!","TWN":"等等，克洛伊！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"저 남자 얼굴 기억 안 나? 리플레이서 사건 때 우리 회사를 습격했던 사람이야!","JPN":"あの男の顔、覚えてる？　リプレイサー事件のとき、私たちの会社を襲撃したあの人だよ！","ENG":"Don't you remember his face? He's the guy who attacked our company during the Replacer incident!","TWN":"那個男的，是克隆集團事件時襲擊我們公司的那個人！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"……역마살이 낀 관상. 양자 관상학적으로 지극히 위험한 인물입니다.","JPN":"……駅馬殺の相が出ています。量子観相学的に見て極めて危険な人物です。","ENG":"...I see endless wandering in his fate. From a Quantum Astrology perspective, he is extremely dangerous.","TWN":"……命帶驛馬的面相，從量子占星術來看，是個極其危險的人物。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"어째서 여기 있는 거지? 설마 부사장님께 그 때 복수를 하려고?","JPN":"なんでここに？　まさか副社長にあのときの復讐をしに来たとか？","ENG":"Why is he here? Is he here to take vengeance on the Vice President?","TWN":"他怎麼會在這裡？難道是因為那個時候的事情想要報復副總？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이런. 생각해 보니 직원 분들께 남긴 첫 인상이 조금 안 좋았죠.","JPN":"おっと、そういえば社員の皆さんは僕の第一印象があまりよくありませんでしたね。","ENG":"Oh dear. Come to think of it, I didn’t really leave a good impression before.","TWN":"哎呀，看來我給職員們留下的第一印象有點不好呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그럼 저는 이만 가 보도록 하겠습니다.","JPN":"では、僕はこれで。","ENG":"Well, then. I should leave now.","TWN":"那我就先走了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"너무 오래 자리를 비우면 동업자 분께서 또 무슨 사고를 치실지 모르니까요.","JPN":"あまり長いこと留守にしていると、同業者の方がまたどんなことをやらかすかわかりませんからね。","ENG":"You never know what trouble my partner might get into.","TWN":"離開太久的話，我的那個合作夥伴說不定會闖什麼禍。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……서로에게 건투를 빌어야겠네요. 하하.","JPN":"……お互い健闘を祈りましょう。ハハ。","ENG":"...I guess we should wish each other the best of luck. Ha ha.","TWN":"……看來要祝彼此好運了呢，哈哈。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"도, 도망치잖아!","JPN":"に、逃げようとしてるよ！","ENG":"H-he's running away!","TWN":"跑，跑了！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"어떡하지? 함포라도 쏴서 막아야 할까?","JPN":"どうしよう？　艦砲でも撃って止めた方がいいかな？","ENG":"What should we do? Should we fire cannons and stop him?","TWN":"怎麼辦？要發射艦炮攔住他嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"함선에 전투원은 한 명도 없습니다, 레나 양.","JPN":"艦船に戦闘員は一人もいませんよ。レナ。","ENG":"There are no combatants in this ship, Lena.","TWN":"艦船上一名戰鬥人員都沒有，蕾娜。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"그리고 화면을 자세히 보세요. 부사장님을 부축하고 있는 사람이 있습니다.","JPN":"それに画面をよく見てみてください。副社長を支えている人がいます。","ENG":"Besides, look at the screen. There's someone carrying the Vice President.","TWN":"而且你好好看看畫面。有個人在扶著副總。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"어? 정말이네?","JPN":"あれ？　本当だ。","ENG":"Huh? You're right.","TWN":"咦？是真的！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"잠깐, 그 옆에 저 상자는…… 사장님?","JPN":"待って、隣のあの箱は……社長？","ENG":"Wait, that box next to them... Is that Boss?","TWN":"而且，他們旁邊的那個箱子是……老闆？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흠, 레나 양? 들리나?","JPN":"ふむ、レナ君？　聞こえているか？","ENG":"Hmm, Lena? Do you hear me?","TWN":"嗯，蕾娜？能聽到我說話嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"누, 누구신데 사장님이랑 같이 계시는 거죠?","JPN":"ど、どちら様ですか？　なんで社長と一緒に居るんですか？","ENG":"W-who are you? Why are you with our Boss?","TWN":"你，你是誰，老闆和你在一起吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"어떻게 된 일인지 모르겠지만, 방금 사라진 남자의 동료가 아니라면 부사장님을 저희에게 인계해 주세요.","JPN":"どういう経緯かはわかりませんけど、今消えていった男の仲間じゃないなら、副社長を私たちに引き渡してください。","ENG":"I don't know what's going on, but if you are not an ally of the man who just disappeared, you’d better give back our Vice President.","TWN":"雖然不知道是怎麼回事，但如果你不是剛才離開的那個男人的同伴，就請把副總交給我們。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"코핀 컴퍼니는 불필요한 교전을 벌일 의사가 없습니다.","JPN":"コフィンカンパニーは不必要な交戦を行うつもりはありません。","ENG":"Coffin Company has no intentions of going through unnecessary combat.","TWN":"科芬公司不想展開不必要的交火。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 믿음직스럽군. 장래에는 함장직을 맡아도 이상하지 않겠어.","JPN":"はは、立派だな。将来的には艦長を任されてもおかしくなさそうだ。","ENG":"Ha ha, very good. I wouldn't be surprised if you were to be the next captain.","TWN":"哈哈，很可靠啊。將來能夠當上艦長，我也不會驚訝了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"그렇게 어물쩡 넘어간다고 될 일이 아니잖아요! 누구시길래……!","JPN":"そうやってうやむやにしてやり過ごそうとしても無駄です！　いったいどなた……！","ENG":"Don't try to slide past this! Who are–","TWN":"哎？你休想這樣蒙混過關！你到底是誰……！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"앗! 아빠! 어디 갔었어?","JPN":"あっ！　パパ！　どこに行ってたの？","ENG":"Ah, Daddy! Where were you?","TWN":"啊，爸爸！你去哪兒了？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미안하다, 시그마. 언니들 힘들지 않게 얌전히 있었지?","JPN":"すまんな、シグマ。お姉さんたちを困らせないように大人しくしていたかな？","ENG":"I'm sorry, Sigma. I hope you've been docile, without troubling the other girls.","TWN":"對不起，西格瑪。你有乖乖聽話，不讓姊姊們累到吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"그럼~ 밖에서 쿵쾅쿵쾅하는데도 꾹 참았다?","JPN":"もちろん～！　外がドカンドカンとうるさくてもグっと堪えたよ？","ENG":"Of course! I stayed put, even with all the noise outside!","TWN":"那當然～外面轟隆轟隆的，我都忍住了喔？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"……아빠라니요, 실장님? 저 남자 분이요?","JPN":"……パパって、室長？　あの男性がですか？","ENG":"…Did you say Daddy, Chief? That man?","TWN":"……爸爸，室長？那個男人？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠, 우선 함선에 태워 주지 않겠나? 날이 춥군.","JPN":"こほん、とりあえず艦船に乗せてくれないか？　今日は寒いのでね。","ENG":"Ahem, won't you be kind and let me inside the ship first? It's cold out here.","TWN":"咳咳，能先讓我上艦船嗎？外面挺冷的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내 소개는 부사장을 병상에 눕힌 뒤에 들어도 충분할 것 같네만.","JPN":"私の紹介は副社長をベッドに寝かせてからでも遅くはないと思うのだが。","ENG":"It won't be late to introduce myself after we've taken care of the Vice President.","TWN":"先把副總安頓好，然後再聽我做自我介紹也來得及。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};